#include "ssd1680_eink.h"
#include <GxEPD2_BW.h>
#include <Fonts/FreeMonoBold9pt7b.h>
static GxEPD2_BW<GxEPD2_213_BN,GxEPD2_213_BN::HEIGHT> disp(GxEPD2_213_BN(5,17,16,4));
void eink_setup(){disp.init(115200);disp.setRotation(1);disp.setTextColor(GxEPD_BLACK);disp.setFont(&FreeMonoBold9pt7b);Serial.println("[eink] OK");}
void eink_clear(){disp.setFullWindow();disp.firstPage();do{disp.fillScreen(GxEPD_WHITE);}while(disp.nextPage());}
void eink_text(int x,int y,const char*t,int s){disp.setTextSize(s);disp.setCursor(x,y);disp.print(t);}
void eink_update(){disp.display();}
